import numpy as np

class NeuralNetwork:
    def __init__(self, input_dim, output_dim, hidden_dims, activations):
        self.input_dim = input_dim
        self.output_dim = output_dim
        self.hidden_dims = hidden_dims
        self.activations = activations
        self.weights = []
        self.biases = []

        # Initialize weights and biases for each layer
        layer_dims = [input_dim] + hidden_dims + [output_dim]
        for i in range(len(layer_dims) - 1):
            self.weights.append(np.random.rand(layer_dims[i], layer_dims[i+1]))
            self.biases.append(np.random.rand(layer_dims[i+1]))

    def sigmoid(self, x):
        return 1 / (1 + np.exp(-x))

    def sigmoid_derivative(self, x):
        return x * (1 - x)

    def relu(self, x):
        return np.maximum(0, x)

    def relu_derivative(self, x):
        return np.where(x > 0, 1, 0)

    def softmax(self, x):
        e_x = np.exp(x - np.max(x))
        return e_x / e_x.sum(axis=0)

    def forward(self, inputs):
        outputs = inputs
        hidden_outputs = []
        for i in range(len(self.weights)):
            weighted_sum = np.dot(outputs, self.weights[i]) + self.biases[i]
            if self.activations[i] == 'sigmoid':
                outputs = self.sigmoid(weighted_sum)
            elif self.activations[i] == 'relu':
                outputs = self.relu(weighted_sum)
            elif self.activations[i] == 'softmax':
                outputs = self.softmax(weighted_sum)
            hidden_outputs.append(outputs)
        return outputs, hidden_outputs

    def compute_gradients(self, inputs, targets, outputs, hidden_outputs):
        gradients = []
        output_error = targets - outputs
        for i in reversed(range(len(self.weights))):
            if self.activations[i] == 'sigmoid':
                derivative = self.sigmoid_derivative(hidden_outputs[i])
            elif self.activations[i] == 'relu':
                derivative = self.relu_derivative(hidden_outputs[i])
            elif self.activations[i] == 'softmax':
                derivative = hidden_outputs[i] * (1 - hidden_outputs[i])
            if i == len(self.weights) - 1:
                error = output_error * derivative
            else:
                error = np.dot(error, self.weights[i+1].T) * derivative
            weight_gradient = np.dot(hidden_outputs[i-1].T if i > 0 else inputs.T, error)
            bias_gradient = error.sum(axis=0)
            gradients.append((weight_gradient, bias_gradient))
        return list(reversed(gradients))

    def update_weights(self, gradients, learning_rate):
        for i in range(len(self.weights)):
            self.weights[i] -= learning_rate * gradients[i][0]
            self.biases[i] -= learning_rate * gradients[i][1]

    def train(self, inputs, targets, learning_rate, num_iterations):
        for _ in range(num_iterations):
            outputs, hidden_outputs = self.forward(inputs)
            gradients = self.compute_gradients(inputs, targets, outputs, hidden_outputs)
            self.update_weights(gradients, learning_rate)

    def evaluate(self, inputs):
        outputs, _ = self.forward(inputs)
        return outputs

