import numpy as np

class NeuralNetwork:
    def __init__(self, input_dim, hidden_dims, output_dim):
        self.input_dim = input_dim
        self.hidden_dims = hidden_dims
        self.output_dim = output_dim
        self.weights = []
        self.bias = []
        self.activations = []
        self.initialize_weights()

    def initialize_weights(self):
        layers = [self.input_dim] + self.hidden_dims + [self.output_dim]
        for i in range(len(layers) - 1):
            self.weights.append(np.random.rand(layers[i], layers[i + 1]))
            self.bias.append(np.zeros((1, layers[i + 1])))
            if i < len(layers) - 2:
                self.activations.append(self.relu)
            else:
                self.activations.append(self.sigmoid)

    def forward(self, inputs):
        outputs = inputs
        self.hiddens = []
        for i in range(len(self.weights)):
            z = np.dot(outputs, self.weights[i]) + self.bias[i]
            outputs = self.activations[i](z)
            self.hiddens.append(outputs)
        return outputs

    def relu(self, x):
        return np.maximum(x, 0)

    def sigmoid(self, x):
        return 1 / (1 + np.exp(-x))

    def mse(self, y_pred, y_true):
        return np.mean((y_pred - y_true) ** 2)

    def cross_entropy(self, y_pred, y_true):
        return -np.mean(y_true * np.log(y_pred) + (1 - y_true) * np.log(1 - y_pred))

    def backward(self, inputs, y_pred, y_true, learning_rate):
        dw = [np.zeros_like(w) for w in self.weights]
        db = [np.zeros_like(b) for b in self.bias]
        error = y_pred - y_true
        for i in reversed(range(len(self.weights))):
            if self.activations[i] == self.relu:
                error = error * (self.hiddens[i] > 0).astype(int)
            elif self.activations[i] == self.sigmoid:
                error = error * self.hiddens[i] * (1 - self.hiddens[i])
            dw[i] = np.dot(self.hiddens[i - 1].T if i > 0 else inputs.T, error)
            db[i] = np.sum(error, axis=0, keepdims=True)
            error = np.dot(error, self.weights[i].T)
        for i in range(len(self.weights)):
            self.weights[i] -= learning_rate * dw[i]
            self.bias[i] -= learning_rate * db[i]

    def train(self, X, y, epochs, learning_rate, loss_func='mse'):
        if loss_func == 'mse':
            for _ in range(epochs):
                y_pred = self.forward(X)
                loss = self.mse(y_pred, y)
                self.backward(X, y_pred, y, learning_rate)
                print(f'Epoch {_ + 1}, Loss: {loss}')
        elif loss_func == 'cross_entropy':
            for _ in range(epochs):
                y_pred = self.forward(X)
                loss = self.cross_entropy(y_pred, y)
                self.backward(X, y_pred, y, learning_rate)
                print(f'Epoch {_ + 1}, Loss: {loss}')


