import numpy as np

class Layer:
    def __init__(self, input_dim, output_dim):
        self.weights = np.random.rand(input_dim, output_dim)
        self.bias = np.zeros((1, output_dim))

    def forward(self, x):
        return np.dot(x, self.weights) + self.bias

    def backward(self, x, dy):
        dw = np.dot(x.T, dy)
        db = np.sum(dy, axis=0, keepdims=True)
        return dw, db

class Activation:
    def __init__(self, activation_type):
        self.activation_type = activation_type

    def forward(self, x):
        if self.activation_type == 'relu':
            return np.maximum(x, 0)
        elif self.activation_type == 'sigmoid':
            return 1 / (1 + np.exp(-x))
        elif self.activation_type == 'tanh':
            return np.tanh(x)

    def backward(self, x, dy):
        if self.activation_type == 'relu':
            return dy * (x > 0).astype(int)
        elif self.activation_type == 'sigmoid':
            return dy * x * (1 - x)
        elif self.activation_type == 'tanh':
            return dy * (1 - x ** 2)

class NeuralNetwork:
    def __init__(self, input_dim, output_dim, hidden_layers):
        self.layers = []
        self.activations = []
        self.input_dim = input_dim
        self.output_dim = output_dim
        prev_dim = input_dim
        for dim in hidden_layers:
            self.layers.append(Layer(prev_dim, dim))
            self.activations.append(Activation('relu'))
            prev_dim = dim
        self.layers.append(Layer(prev_dim, output_dim))
        self.activations.append(Activation('sigmoid'))

    def forward(self, x):
        for i in range(len(self.layers)):
            x = self.layers[i].forward(x)
            if i < len(self.layers) - 1:
                x = self.activations[i].forward(x)
            else:
                x = self.activations[i].forward(x)
        return x

    def backward(self, x, y):
        dy = y - self.forward(x)
        dys = []
        for i in range(len(self.layers) - 1, -1, -1):
            if i == len(self.layers) - 1:
                dy = self.activations[i].backward(self.layers[i].forward(x), dy)
            else:
                dy = self.activations[i].backward(self.layers[i].forward(x), dy)
            dw, db = self.layers[i].backward(x if i == 0 else self.layers[i-1].forward(x), dy)
            dys.append((dw, db))
            x = self.layers[i-1].forward(x) if i > 0 else x
        return dys

    def train(self, x, y, learning_rate, epochs):
        for _ in range(epochs):
            dys = self.backward(x, y)
            for i in range(len(self.layers)):
                dw, db = dys[len(self.layers) - i - 1]
                self.layers[i].weights -= learning_rate * dw
                self.layers[i].bias -= learning_rate * db

    def predict(self, x):
        return self.forward(x)

