import numpy as np

class Layer:
    def __init__(self, input_size, output_size):
        self.weights = np.random.rand(input_size, output_size)
        self.bias = np.zeros((1, output_size))

    def forward(self, input_data):
        self.input_data = input_data
        return np.dot(input_data, self.weights) + self.bias

    def backward(self, error):
        weights_error = np.dot(self.input_data.T, error)
        bias_error = np.sum(error, axis=0, keepdims=True)
        return np.dot(error, self.weights.T), weights_error, bias_error


class Activation:
    def __init__(self, type):
        self.type = type

    def forward(self, input_data):
        if self.type == 'relu':
            return np.maximum(input_data, 0)
        elif self.type == 'sigmoid':
            return 1 / (1 + np.exp(-input_data))
        elif self.type == 'tanh':
            return np.tanh(input_data)

    def backward(self, error):
        if self.type == 'relu':
            return error * (self.input_data > 0).astype(int)
        elif self.type == 'sigmoid':
            return error * self.output_data * (1 - self.output_data)
        elif self.type == 'tanh':
            return error * (1 - self.output_data ** 2)

    def forward_and_save(self, input_data):
        self.input_data = input_data
        self.output_data = self.forward(input_data)
        return self.output_data


class NeuralNetwork:
    def __init__(self, input_size, output_size, hidden_layers):
        self.layers = []
        self.layers.append(Layer(input_size, hidden_layers[0]))
        for i in range(len(hidden_layers) - 1):
            self.layers.append(Layer(hidden_layers[i], hidden_layers[i + 1]))
        self.layers.append(Layer(hidden_layers[-1], output_size))
        self.activations = [Activation('relu') for _ in range(len(hidden_layers))]

    def forward(self, input_data):
        output = input_data
        for i in range(len(self.layers) - 1):
            output = self.layers[i].forward(output)
            output = self.activations[i].forward_and_save(output)
        output = self.layers[-1].forward(output)
        return output

    def backward(self, error):
        errors = [error]
        for i in range(len(self.layers) - 1, 0, -1):
            error = self.layers[i].backward(error)[0]
            error *= self.activations[i - 1].backward(error)
            errors.append(error)
        return errors

    def train(self, input_data, output_data, learning_rate, epochs):
        for _ in range(epochs):
            output = self.forward(input_data)
            error = output - output_data
            errors = self.backward(error)
            for i in range(len(self.layers)):
                weights_error, bias_error = self.layers[i].backward(errors[-i - 1])[1:]
                self.layers[i].weights -= learning_rate * weights_error
                self.layers[i].bias -= learning_rate * bias_error


