import numpy as np

class NeuralNetwork:
    def __init__(self, input_dim, output_dim, hidden_layers):
        self.input_dim = input_dim
        self.output_dim = output_dim
        self.hidden_layers = hidden_layers
        self.weights = []
        self.biases = []
        self.activations = []
        self.layers = [input_dim] + hidden_layers + [output_dim]

        for i in range(len(self.layers) - 1):
            self.weights.append(np.random.rand(self.layers[i], self.layers[i + 1]))
            self.biases.append(np.zeros((1, self.layers[i + 1])))
            if i < len(self.layers) - 2:
                self.activations.append(self.relu)
            else:
                self.activations.append(self.sigmoid)

    def relu(self, x):
        return np.maximum(x, 0)

    def sigmoid(self, x):
        return 1 / (1 + np.exp(-x))

    def forward_pass(self, inputs):
        outputs = [inputs]
        for i in range(len(self.weights)):
            weighted_sum = np.dot(outputs[-1], self.weights[i]) + self.biases[i]
            outputs.append(self.activations[i](weighted_sum))
        return outputs

    def backward_pass(self, inputs, targets, outputs, learning_rate):
        errors = [targets - outputs[-1]]
        for i in range(len(self.weights) - 1, -1, -1):
            if i < len(self.weights) - 1:
                errors.append(np.dot(errors[-1], self.weights[i + 1].T) * self.relu_derivative(outputs[i + 1]))
            else:
                errors.append(np.dot(errors[-1], self.weights[i + 1].T))
        for i in range(len(self.weights)):
            self.weights[i] += learning_rate * np.dot(outputs[i].T, errors[-i - 1])
            self.biases[i] += learning_rate * np.sum(errors[-i - 1], axis=0, keepdims=True)

    def relu_derivative(self, x):
        return (x > 0).astype(int)

    def sigmoid_derivative(self, x):
        return x * (1 - x)

    def train(self, inputs, targets, learning_rate, epochs):
        for _ in range(epochs):
            outputs = self.forward_pass(inputs)
            self.backward_pass(inputs, targets, outputs, learning_rate)

    def predict(self, inputs):
        outputs = self.forward_pass(inputs)
        return outputs[-1]

