import numpy as np

class NeuralNetwork:
    def __init__(self, input_dim, output_dim, hidden_layers):
        self.input_dim = input_dim
        self.output_dim = output_dim
        self.hidden_layers = hidden_layers
        self.weights = []
        self.biases = []
        self.activations = []

        # Initialize weights and biases for each layer
        for i in range(len(hidden_layers) + 1):
            if i == 0:
                self.weights.append(np.random.rand(input_dim, hidden_layers[i]))
                self.biases.append(np.zeros((1, hidden_layers[i])))
            elif i == len(hidden_layers):
                self.weights.append(np.random.rand(hidden_layers[i-1], output_dim))
                self.biases.append(np.zeros((1, output_dim)))
            else:
                self.weights.append(np.random.rand(hidden_layers[i-1], hidden_layers[i]))
                self.biases.append(np.zeros((1, hidden_layers[i])))

        # Initialize activations for each layer
        self.activations = ['relu'] * len(hidden_layers) + ['sigmoid']

    def sigmoid(self, x):
        return 1 / (1 + np.exp(-x))

    def relu(self, x):
        return np.maximum(x, 0)

    def sigmoid_derivative(self, x):
        return x * (1 - x)

    def relu_derivative(self, x):
        return (x > 0).astype(int)

    def forward_pass(self, inputs):
        outputs = []
        for i in range(len(self.hidden_layers) + 1):
            if i == 0:
                output = np.dot(inputs, self.weights[i]) + self.biases[i]
            else:
                output = np.dot(outputs[i-1], self.weights[i]) + self.biases[i]

            if self.activations[i] == 'sigmoid':
                output = self.sigmoid(output)
            elif self.activations[i] == 'relu':
                output = self.relu(output)

            outputs.append(output)

        return outputs

    def backward_pass(self, inputs, targets, learning_rate):
        outputs = self.forward_pass(inputs)
        errors = [None] * (len(self.hidden_layers) + 1)
        weight_gradients = [None] * (len(self.hidden_layers) + 1)
        bias_gradients = [None] * (len(self.hidden_layers) + 1)

        # Calculate error for output layer
        if self.activations[-1] == 'sigmoid':
            errors[-1] = (targets - outputs[-1]) * self.sigmoid_derivative(outputs[-1])
        elif self.activations[-1] == 'relu':
            errors[-1] = (targets - outputs[-1]) * self.relu_derivative(outputs[-1])

        # Calculate weight and bias gradients for output layer
        weight_gradients[-1] = np.dot(outputs[-2].T, errors[-1])
        bias_gradients[-1] = np.sum(errors[-1], axis=0, keepdims=True)

        # Calculate errors, weight gradients, and bias gradients for hidden layers
        for i in range(len(self.hidden_layers) - 1, -1, -1):
            if self.activations[i] == 'sigmoid':
                errors[i] = np.dot(errors[i+1], self.weights[i+1].T) * self.sigmoid_derivative(outputs[i])
            elif self.activations[i] == 'relu':
                errors[i] = np.dot(errors[i+1], self.weights[i+1].T) * self.relu_derivative(outputs[i])

            if i == 0:
                weight_gradients[i] = np.dot(inputs.T, errors[i])
                bias_gradients[i] = np.sum(errors[i], axis=0, keepdims=True)
            else:
                weight_gradients[i] = np.dot(outputs[i-1].T, errors[i])
                bias_gradients[i] = np.sum(errors[i], axis=0, keepdims=True)

        # Update weights and biases
        for i in range(len(self.hidden_layers) + 1):
            self.weights[i] += learning_rate * weight_gradients[i]
            self.biases[i] += learning_rate * bias_gradients[i]

        return np.mean(np.square(targets - outputs[-1]))

