            if i == self.num_hidden_layers - 1:
                self.errors[i] = np.dot(self.errors[i + 1], self.weights[i + 1].T) * self.relu_derivative(self.layer_outputs[i])
            else:
                self.errors[i] = np.dot(self.errors[i + 1], self.weights[i + 1].T) * self.relu_derivative(self.layer_outputs[i])

        for i in range(self.num_hidden_layers + 1):
            if i == self.num_hidden_layers:
                self.weights[i] += learning_rate * np.dot(self.layer_outputs[i - 1].T, (2 * self.errors[i]))
                self.biases[i] += learning_rate * np.sum(self.errors[i], axis=0, keepdims=True)
            else:
                self.weights[i] += learning_rate * np.dot(self.layer_outputs[i - 1].T, self.errors[i])
                self.biases[i] += learning_rate * np.sum(self.errors[i], axis=0, keepdims=True)

    def train(self, inputs, targets, learning_rate, num_iterations):
        for _ in range(num_iterations):
            self.forward_pass(inputs)
            self.backward_pass(targets, learning_rate)

    def predict(self, inputs):
