import numpy as np

class Layer:
    def __init__(self, inputs, neurons, activation=None):
        self.inputs = inputs
        self.neurons = neurons
        self.activation = activation
        self.weights = np.random.rand(inputs, neurons)
        self.bias = np.zeros((1, neurons))

    def forward(self, x):
        self.output = np.dot(x, self.weights) + self.bias
        if self.activation == 'relu':
            self.output = np.maximum(self.output, 0)
        elif self.activation == 'sigmoid':
            self.output = 1 / (1 + np.exp(-self.output))
        return self.output

    def backward(self, error, learning_rate):
        if self.activation == 'relu':
            d_output = np.where(self.output > 0, 1, 0)
        elif self.activation == 'sigmoid':
            d_output = self.output * (1 - self.output)
        d_weights = np.dot(error * d_output, self.weights.T)
        d_bias = np.sum(error * d_output, axis=0, keepdims=True)
        self.weights -= learning_rate * d_weights
        self.bias -= learning_rate * d_bias
        return d_output

class Network:
    def __init__(self):
        self.layers = []

    def add_layer(self, inputs, neurons, activation=None):
        self.layers.append(Layer(inputs, neurons, activation))

    def forward(self, x):
        for layer in self.layers:
            x = layer.forward(x)
        return x

    def backward(self, error, learning_rate):
        for layer in reversed(self.layers):
            error = layer.backward(error, learning_rate)

    def train(self, x_train, y_train, learning_rate, epochs):
        for _ in range(epochs):
            output = self.forward(x_train)
            error = y_train - output
            self.backward(error, learning_rate)

    def predict(self, x_test):
        return self.forward(x_test)

