class NeuralNetwork:
    def __init__(self, input_dim, output_dim, hidden_dim, num_hidden_layers, activation='sigmoid'):
        self.input_dim = input_dim
        self.output_dim = output_dim
        self.hidden_dim = hidden_dim
        self.num_hidden_layers = num_hidden_layers
        self.activation = activation
        self.weights = []
        self.biases = []

        for i in range(num_hidden_layers + 1):
            if i == 0:
                self.weights.append(np.random.rand(input_dim, hidden_dim))
                self.biases.append(np.zeros((1, hidden_dim)))
            elif i == num_hidden_layers:
                self.weights.append(np.random.rand(hidden_dim, output_dim))
                self.biases.append(np.zeros((1, output_dim)))
            else:
                self.weights.append(np.random.rand(hidden_dim, hidden_dim))
                self.biases.append(np.zeros((1, hidden_dim)))

    def sigmoid(self, x):
        return 1 / (1 + np.exp(-x))

    def sigmoid_derivative(self, x):
        return x * (1 - x)

    def relu(self, x):
        return np.maximum(x, 0)

    def relu_derivative(self, x):
        return np.where(x > 0, 1, 0)

    def forward_pass(self, inputs):
        outputs = []
        for i in range(self.num_hidden_layers + 1):
            if i == 0:
                output = np.dot(inputs, self.weights[i]) + self.biases[i]
            else:
                output = np.dot(outputs[-1], self.weights[i]) + self.biases[i]

            if self.activation == 'sigmoid':
                output = self.sigmoid(output)
            elif self.activation == 'relu':
                output = self.relu(output)

            outputs.append(output)

        return outputs

    def backpropagation(self, inputs, targets, learning_rate):
        outputs = self.forward_pass(inputs)
        errors = [0] * (self.num_hidden_layers + 1)
        delta_weights = [0] * (self.num_hidden_layers + 1)
        delta_biases = [0] * (self.num_hidden_layers + 1)

        errors[-1] = targets - outputs[-1]
        if self.activation == 'sigmoid':
            delta_weights[-1] = np.dot(outputs[-2].T, errors[-1] * self.sigmoid_derivative(outputs[-1]))
            delta_biases[-1] = np.sum(errors[-1] * self.sigmoid_derivative(outputs[-1]), axis=0, keepdims=True)
        elif self.activation == 'relu':
