import numpy as np

class Layer:
    def __init__(self, neurons, inputs, activation=None):
        self.neurons = neurons
        self.inputs = inputs
        self.activation = activation
        self.weights = np.random.rand(inputs, neurons)
        self.bias = np.zeros((1, neurons))

    def forward(self, x):
        self.output = np.dot(x, self.weights) + self.bias
        if self.activation == 'sigmoid':
            self.output = 1 / (1 + np.exp(-self.output))
        elif self.activation == 'relu':
            self.output = np.maximum(self.output, 0)
        return self.output

    def backward(self, error, learning_rate):
        if self.activation == 'sigmoid':
            d_output = error * self.output * (1 - self.output)
        elif self.activation == 'relu':
            d_output = error * (self.output > 0).astype(int)
        else:
            d_output = error
        d_weights = np.dot(error.T, self.output)
        d_bias = np.sum(error, axis=0, keepdims=True)
        self.weights -= learning_rate * d_weights
        self.bias -= learning_rate * d_bias
        return np.dot(d_output, self.weights.T)

class Network:
    def __init__(self, layers):
        self.layers = layers

    def forward(self, x):
        for layer in self.layers:
            x = layer.forward(x)
        return x

    def backward(self, error, learning_rate):
        for layer in reversed(self.layers):
            error = layer.backward(error, learning_rate)

    def train(self, x, y, learning_rate, epochs):
        for _ in range(epochs):
            output = self.forward(x)
            error = y - output
            self.backward(error, learning_rate)

