    def relu_derivative(self, x):
        return np.where(x > 0, 1, 0)

    def tanh(self, x):
        return np.tanh(x)

    def tanh_derivative(self, x):
        return 1 - np.tanh(x) ** 2

    def forward_pass(self, inputs, activation_functions):
        outputs = inputs
        for i in range(len(self.weights)):
            outputs = np.dot(outputs, self.weights[i]) + self.biases[i]
            if activation_functions[i] == 'sigmoid':
                outputs = self.sigmoid(outputs)
            elif activation_functions[i] == 'relu':
                outputs = self.relu(outputs)
            elif activation_functions[i] == 'tanh':
                outputs = self.tanh(outputs)
        return outputs

    def backpropagation(self, inputs, targets, activation_functions, learning_rate):
        outputs = inputs
        output_layers = []
        for i in range(len(self.weights)):
            outputs = np.dot(outputs, self.weights[i]) + self.biases[i]
            if activation_functions[i] == 'sigmoid':
                outputs = self.sigmoid(outputs)
            elif activation_functions[i] == 'relu':
                outputs = self.relu(outputs)
            elif activation_functions[i] == 'tanh':
                outputs = self.tanh(outputs)
            output_layers.append(outputs)

        error = targets - output_layers[-1]
        if activation_functions[-1] == 'sigmoid':
            delta = error * self.sigmoid_derivative(output_layers[-1])
        elif activation_functions[-1] == 'relu':
            delta = error * self.relu_derivative(output_layers[-1])
        elif activation_functions[-1] == 'tanh':
            delta = error * self.tanh_derivative(output_layers[-1])

        for i in range(len(self.weights) - 1, -1, -1):
            self.weights[i] += learning_rate * np.dot(output_layers[i - 1].T if i > 0 else inputs.T, delta)
            self.biases[i] += learning_rate * np.sum(delta, axis=0, keepdims=True)
            if i > 0:
                if activation_functions[i - 1] == 'sigmoid':
                    delta = np.dot(delta, self.weights[i].T) * self.sigmoid_derivative(output_layers[i - 1])
                elif activation_functions[i - 1] == 'relu':
                    delta = np.dot(delta, self.weights[i].T) * self.relu_derivative(output_layers[i - 1])
                elif activation_functions[i - 1] == 'tanh':
                    delta = np.dot(delta, self.weights[i].T) * self.tanh_derivative(output_layers[i - 1])

    def train(self, inputs, targets, activation_functions, learning_rate, epochs):
        for _ in range(epochs):
            self.backpropagation(inputs, targets, activation_functions, learning_rate)

    def predict(self, inputs, activation_functions):
        return self.forward_pass(inputs, activation_functions)


