import numpy as np

class NeuralNetwork:
    def __init__(self, input_dim, output_dim, hidden_dim, num_hidden_layers, activation='sigmoid', output_activation='sigmoid'):
        self.input_dim = input_dim
        self.output_dim = output_dim
        self.hidden_dim = hidden_dim
        self.num_hidden_layers = num_hidden_layers
        self.activation = activation
        self.output_activation = output_activation
        self.weights = []
        self.biases = []
        self.initialize_weights_and_biases()

    def initialize_weights_and_biases(self):
        self.weights.append(np.random.rand(self.input_dim, self.hidden_dim))
        self.biases.append(np.zeros((1, self.hidden_dim)))
        for _ in range(self.num_hidden_layers - 1):
            self.weights.append(np.random.rand(self.hidden_dim, self.hidden_dim))
            self.biases.append(np.zeros((1, self.hidden_dim)))
        self.weights.append(np.random.rand(self.hidden_dim, self.output_dim))
        self.biases.append(np.zeros((1, self.output_dim)))

    def sigmoid(self, x):
        return 1 / (1 + np.exp(-x))

    def sigmoid_derivative(self, x):
        return x * (1 - x)

    def relu(self, x):
        return np.maximum(x, 0)

    def relu_derivative(self, x):
        return np.where(x > 0, 1, 0)

    def forward_propagate(self, inputs):
        outputs = []
        for i in range(len(self.weights)):
            if i == 0:
                output = np.dot(inputs, self.weights[i]) + self.biases[i]
            else:
                output = np.dot(outputs[-1], self.weights[i]) + self.biases[i]
            if i == len(self.weights) - 1:
                if self.output_activation == 'sigmoid':
                    output = self.sigmoid(output)
                elif self.output_activation == 'relu':
                    output = self.relu(output)
            else:
                if self.activation == 'sigmoid':
                    output = self.sigmoid(output)
                elif self.activation == 'relu':
                    output = self.relu(output)
            outputs.append(output)
        return outputs

    def back_propagate(self, inputs, targets, learning_rate):
        outputs = self.forward_propagate(inputs)
        errors = [None] * len(self.weights)
        for i in range(len(self.weights) - 1, -1, -1):
            if i == len(self.weights) - 1:
                error = targets - outputs[i]
            else:
                error = np.dot(errors[i + 1], self.weights[i + 1].T)
            if i == len(self.weights) - 1:
                if self.output_activation == 'sigmoid':
                    delta = error * self.sigmoid_derivative(outputs[i])
                elif self.output_activation == 'relu':
                    delta = error * self.relu_derivative(outputs[i])
            else:
                if self.activation == 'sigmoid':
                    delta = error * self.sigmoid_derivative(outputs[i])
                elif self.activation == 'relu':
                    delta = error * self.relu_derivative(outputs[i])
            if i == 0:
                self.weights[i] += learning_rate * np.dot(inputs.T, delta)
                self.biases[i] += learning_rate * np.sum(delta, axis=0, keepdims=True)
            else:
                self.weights[i] += learning_rate * np.dot(outputs[i - 1].T, delta)
                self.biases[i] += learning_rate * np.sum(delta, axis=0, keepdims=True)
            errors[i] = delta

    def train(self, inputs, targets, learning_rate, num_iterations):
        for _ in range(num_iterations):
            self.back_propagate(inputs, targets, learning_rate)

    def predict(self, inputs):
        outputs = self.forward_propagate(inputs)
        return outputs[-1]

