class Jet1Ir:
    def __init__(self, max_depth, learning_rate, num_trees):
        self.max_depth = max_depth
        self.learning_rate = learning_rate
        self.num_trees = num_trees
        self.trees = []

    def fit(self, X, y):
        for _ in range(self.num_trees):
            tree = {}
            self._build_tree(tree, X, y, self.max_depth)
            self.trees.append(tree)

    def _build_tree(self, tree, X, y, depth):
        if depth == 0 or len(set(y)) == 1:
            tree['value'] = self._calculate_value(y)
            return
        feature = self._choose_feature(X, y)
        tree['feature'] = feature
        tree['left'] = {}
        tree['right'] = {}
        left_X, left_y, right_X, right_y = self._split_data(X, y, feature)
        self._build_tree(tree['left'], left_X, left_y, depth - 1)
        self._build_tree(tree['right'], right_X, right_y, depth - 1)

    def _calculate_value(self, y):
        return sum(y) / len(y)

    def _choose_feature(self, X, y):
        best_feature = 0
        best_score = float('-inf')
        for feature in range(X.shape[1]):
            score = self._calculate_score(X, y, feature)
            if score > best_score:
                best_score = score
                best_feature = feature
        return best_feature

    def _calculate_score(self, X, y, feature):
        left_y, right_y = self._split_labels(y, X[:, feature])
        left_score = self._calculate_gini(left_y)
        right_score = self._calculate_gini(right_y)
        return self._calculate_weighted_score(left_score, right_score)

    def _split_data(self, X, y, feature):
        left_X = X[X[:, feature] < 0.5]
        left_y = y[X[:, feature] < 0.5]
        right_X = X[X[:, feature] >= 0.5]
        right_y = y[X[:, feature] >= 0.5]
        return left_X, left_y, right_X, right_y

    def _split_labels(self, y, feature):
        left_y = y[feature < 0.5]
        right_y = y[feature >= 0.5]
        return left_y, right_y

    def _calculate_gini(self, y):
        p = [len(y[y == c]) / len(y) for c in set(y)]
        return 1 - sum([pi ** 2 for pi in p])

    def _calculate_weighted_score(self, left_score, right_score):
        left_weight = len(left_score) / (len(left_score) + len(right_score))
        right_weight = len(right_score) / (len(left_score) + len(right_score))
        return left_weight * left_score + right_weight * right_score

    def predict(self, X):
        predictions = []
        for tree in self.trees:
            prediction = self._predict_tree(tree, X)
            predictions.append(prediction)
        return sum(predictions) / len(predictions)

    def _predict_tree(self, tree, X):
        if 'value' in tree:
            return tree['value']
        feature = tree['feature']
        if X[feature] < 0.5:
            return self._predict_tree(tree['left'], X)
        else:
            return self._predict_tree(tree['right'], X)

