from abc import ABC, abstractmethod
from enum import Enum
from dataclasses import dataclass
from typing import List

class State(Enum):
    START = 1
    IN_PROGRESS = 2
    COMPLETED = 3

@dataclass
class Task:
    id: int
    name: str
    state: State

class Observer(ABC):
    @abstractmethod
    def update(self, task: Task):
        pass

class User:
    def __init__(self, name: str):
        self.name = name

    def update(self, task: Task):
        print(f"User {self.name} received update: Task {task.id} is {task.state.name}")

class Manager:
    def __init__(self):
        self.observers: List[Observer] = []
        self.tasks: List[Task] = []

    def attach(self, observer: Observer):
        self.observers.append(observer)

    def detach(self, observer: Observer):
        self.observers.remove(observer)

    def notify(self, task: Task):
        for observer in self.observers:
            observer.update(task)

    def add_task(self, task: Task):
        self.tasks.append(task)
        self.notify(task)

    def update_task_state(self, task_id: int, new_state: State):
        for task in self.tasks:
            if task.id == task_id:
                task.state = new_state
                self.notify(task)
                break

# create a manager
manager = Manager()

# create users
user1 = User("John")
user2 = User("Jane")

# attach users to the manager
manager.attach(user1)
manager.attach(user2)

# add a task
task1 = Task(1, "Task 1", State.START)
manager.add_task(task1)

# update task state
manager.update_task_state(1, State.IN_PROGRESS)
manager.update_task_state(1, State.COMPLETED)

