def filter_data(data, column_name, target_value):
    filtered_data = []
    for row in data:
        if row[column_name] == target_value:
            filtered_data.append(row)
    return filtered_data

def aggregate_data(data, column_name):
    aggregated_data = {}
    for row in data:
        key = row[column_name]
        if key in aggregated_data:
            aggregated_data[key] += 1
        else:
            aggregated_data[key] = 1
    return aggregated_data

def transform_data(data, column_name, transformation_function):
    transformed_data = []
    for row in data:
        new_row = row.copy()
        new_row[column_name] = transformation_function(new_row[column_name])
        transformed_data.append(new_row)
    return transformed_data

def load_data(file_path):
    data = []
    with open(file_path, 'r') as file:
        for line in file:
            row = line.strip().split(',')
            data.append(row)
    return data

def main():
    file_path = 'data.csv'
    data = load_data(file_path)
    filtered_data = filter_data(data, 0, 'target_value')
    aggregated_data = aggregate_data(filtered_data, 1)
    transformed_data = transform_data(filtered_data, 2, lambda x: x.upper())
    print(aggregated_data)
    print(transformed_data)

if __name__ == '__main__':
